// index.js

import React from "react";
import { graphql, Link } from "gatsby";
import { LayoutProse } from "src/components/layouts/layout";
import { SeoHome } from "src/components/Seo";
import { HomeCardWrp } from "../components/home/HomeCardWrp";
import { HrIndex } from "src/utils/HorizontalRules";
import { useHomeCardSelector } from "../components/home/useHomeCardSelector";

const IndexPage = ({ data }) => {
  const {
    filteredPub,
    filteredProjects,
    filteredBlogs,
    filteredModels,
    latestPub,
    latestProject,
    latestBlog,
    latestModel,
  } = useHomeCardSelector(data);

  const renderSection = (title, items, itemType, latestItem) => (
    <HomeCardWrp
      title={title}
      items={items}
      itemType={itemType}
      latestItem={latestItem}
    />
  );

  return (
    <LayoutProse pageTitle="">
      <section className="hm-flx">
        <>
          <section id="welcome" className="hm-sec-intro-flx">
            <div className="hm-intro-head">
              <h2>Welcome to my site!</h2>
            </div>
            <div className="g-pretty-p">
              <p>Hello, I am Arnott Ferels.</p>
              <p>
                My expertise lies in designing and integrating innovative{" "}
                <Link to="/search/?q=computation">
                  computational techniques
                </Link>
                ,{" "}
                <Link to="/search/?q=generative">
                  generative design methods
                </Link>
                , and{" "}
                <Link to="/search/?q=optimization">
                  optimization strategies
                </Link>
                , especially within the fields of{" "}
                <Link to="/search/?q=arch">architectural design</Link> and{" "}
                <Link to="/search/?q=urban">urban planning</Link>.
              </p>
              <p>
                I am deeply passionate about{" "}
                <Link to="/search/?q=urban">urban simulation</Link>,{" "}
                <Link to="/search/?q=agent">agent-based modeling</Link>, and{" "}
                <Link to="/search/?q=transit">
                  transit-oriented development (TOD)
                </Link>{" "}
                in my work, contributing to innovative urban solutions.
              </p>
              <p>
                You are welcome to explore my{" "}
                <Link to="/projects">projects</Link>,{" "}
                <Link to="/pub">publications</Link>,{" "}
                <Link to="/models">models</Link>, read my{" "}
                <Link to="/blog">blog</Link>, and discover more about my work.
              </p>
              <p>
                I am enthusiastic about exploring collaboration opportunities to
                transform innovative ideas into tangible realities.
              </p>
            </div>
          </section>
        </>
        <HrIndex />
        {renderSection("Publications", filteredPub, "pub", latestPub)}
        <HrIndex />
        {renderSection("Projects", filteredProjects, "projects", latestProject)}
        <HrIndex />
        {renderSection("Models", filteredModels, "models", latestModel)}
        <HrIndex />
        {renderSection("Blogs", filteredBlogs, "blog", latestBlog)}
        <HrIndex />
      </section>
    </LayoutProse>
  );
};

export const query = graphql`
  query IndexPageQuery {
    allMdx {
      nodes {
        id
        excerpt
        frontmatter {
          p_type
          slug
          issn
          url
          doi
          language
          journal
          author {
            id
            name
          }
          day
          month
          year
          pages
          date(formatString: "MMMM DD, YYYY")
          title
          hero_img_src {
            childImageSharp {
              gatsbyImageData
            }
          }
          abstract
          keywords {
            id
            name
          }
        }
      }
    }
  }
`;

export default IndexPage;

export const Head = () => <SeoHome />;
