import { useState } from "react";

export const KeywordsFilter = (initialNodes, keywordField) => {
  const [selectedKeyword, setSelectedKeyword] = useState(null); // Tracks selected keyword for filtering
  const [showAllKeywords, setShowAllKeywords] = useState(false); // Tracks whether to show all keywords or not

  // Function to toggle selected keyword
  const toggleKeyword = (keyword) => {
    setSelectedKeyword((prevKeyword) =>
      prevKeyword === keyword ? null : keyword,
    ); // Toggle keyword selection
  };

  // Function to toggle showing all keywords
  const toggleShowAllKeywords = () => {
    setShowAllKeywords((prevState) => !prevState);
  };

  // Filter nodes based on selected keyword and specified keywordField
  const filteredNodes = selectedKeyword
    ? initialNodes.filter((node) =>
        node.frontmatter[keywordField].some(
          (kw) => kw.name === selectedKeyword,
        ),
      )
    : initialNodes;

  return {
    selectedKeyword,
    toggleKeyword,
    showAllKeywords,
    toggleShowAllKeywords,
    filteredNodes,
  };
};
