export const useHomeCardSelector = (data) => {
  const { nodes: allNodes } = data.allMdx;
  const pub = allNodes.filter((node) => node.frontmatter.p_type === "pub");
  const projects = allNodes.filter(
    (node) => node.frontmatter.p_type === "projects",
  );
  const blogs = allNodes.filter((node) => node.frontmatter.p_type === "blog");
  const models = allNodes.filter(
    (node) => node.frontmatter.p_type === "models",
  );

  // Manually select the latest publication based on the slug
  const latestPubSlug = "doi/10-1177/14780771241254639"; // Replace with the actual slug
  const latestPub =
    pub.find((pub) => pub.frontmatter.slug === latestPubSlug) || pub[0];

  // Manually select the latest project based on the slug
  const latestProjectSlug = "x-transit-hub"; // Replace with the actual slug
  const latestProject =
    projects.find(
      (project) => project.frontmatter.slug === latestProjectSlug,
    ) || projects[0];

  // Sort and slice blogs by date in descending order to get the latest 5 blogs
  const sortedBlogs = [...blogs]
    .sort((a, b) => new Date(b.frontmatter.date) - new Date(a.frontmatter.date))
    .slice(0, 5);
  const latestBlog = sortedBlogs[0];

  // Sort and slice models by date in descending order to get the latest 5 models
  const sortedModels = [...models]
    .sort((a, b) => new Date(b.frontmatter.date) - new Date(a.frontmatter.date))
    .slice(0, 5);
  const latestModel = sortedModels[0];

  // Exclude the latest items from the filtered lists and limit to 4
  const filteredPub = pub
    .filter((pub) => pub !== latestPub)
    .sort((a, b) => new Date(b.frontmatter.date) - new Date(a.frontmatter.date))
    .slice(0, 4);
  const filteredProjects = projects
    .filter((project) => project !== latestProject)
    .sort((a, b) => new Date(b.frontmatter.date) - new Date(a.frontmatter.date))
    .slice(0, 4);
  const filteredBlogs = sortedBlogs.slice(1);
  const filteredModels = sortedModels.slice(1);

  return {
    filteredPub,
    filteredProjects,
    filteredBlogs,
    filteredModels,
    latestPub,
    latestProject,
    latestBlog,
    latestModel,
  };
};
