// PubFrontmatter.js

import React from "react";

export const PubFrontmatter = ({ p_type, node }) => {
  return (
    <>
      {/* Conditional rendering for p_type 'pub' */}
      {p_type === "pub" && (
        <div className="card-pub-wrp">
          {node.frontmatter.author &&
            Array.isArray(node.frontmatter.author) && (
              <div className="card-pub-aut">
                {node.frontmatter.author
                  .map((author) => {
                    const [firstName, lastName] = author.name.split(" ");
                    return `${firstName} ${lastName}`;
                  })
                  .join(", ")}
              </div>
            )}

          {node.frontmatter.journal && (
            <div className="card-pub-jour">
              {node.frontmatter.journal && <>{node.frontmatter.journal}</>}
              {node.frontmatter.doi && node.frontmatter.url && (
                <>
                  {" — "}
                  <a
                    href={node.frontmatter.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="g-normal-link"
                  >
                    {node.frontmatter.doi}
                  </a>
                </>
              )}
            </div>
          )}
        </div>
      )}
    </>
  );
};
