import React, { useEffect } from "react";
import { Link } from "gatsby";
import { KeywordsFilter } from "src/utils/KeywordsFilter";
import { HomeCard } from "./HomeCard";

export const HomeCardWrp = ({ title, items, itemType, latestItem }) => {
  const { filteredNodes } = KeywordsFilter(items, `${itemType}_keywords`);
  const otherItems = filteredNodes.filter((item) => item !== latestItem);
  const slicedNodes = otherItems.slice(0, 5);

  useEffect(() => {}, [items]);

  return (
    <>
      <section
        id={title.toLowerCase()}
        title={title}
        className="hm-sec-cd-flx"
      >
        {/* Title */}
        <h2 className="hm-sec-pg-cd-tit-wrp">
          <Link to={`/${itemType}`} className="g-hidden-link">
            {title}
          </Link>
        </h2>

        {/* Section (featured and others item) */}
        <section className="hm-sec-cd-item-wrp">
          {/* Featured item */}
          {latestItem && (
            <div className="hm-sec-cd-ft-wrp">
              {HomeCard(latestItem, itemType, true)}
            </div>
          )}

          {/* Other item */}
          {otherItems.length > 0 && (
            <div className="hm-sec-cd-oth-wrp">
              {slicedNodes.map((item, index) => (
                <div key={index} className="hm-cd-oth">
                  {HomeCard(item, itemType, false)}
                </div>
              ))}
            </div>
          )}

          {/* Read more link */}
          <div className="g-rml-wrp">
            <Link to={`/${itemType}`} className="g-action-link">
              Show all {title.toLowerCase()} ...
            </Link>
          </div>
        </section>
      </section>
    </>
  );
};
