// index.js

import React, { useState, useEffect } from "react";
import { GatsbyImage, getImage } from "gatsby-plugin-image";
import { Link } from "gatsby";
import { ReadMoreLink } from "src/utils/ReadMoreLinks";
import { formatFullDateMonthYear, formatMonthYear } from "src/utils/FormatDate";
import { KeywordButtonsGeneral } from "src/utils/KeywordButtons";
import { ShowMoreButton } from "src/utils/ShowMoreButton";
import { PubFrontmatter } from "src/templates/frontmatter/PubFrontmatter";
import PlaceholderImage from "src/assets/placeholder/2000x2000.png";

export const HomeCard = (node, p_type, isFeatured) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const toggleExpand = () => {
    setIsExpanded(!isExpanded);
  };

  const [isMobile, setIsMobile] = useState(false); // Set initial state to false

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.matchMedia("(max-width: 640px)").matches);
    };

    handleResize(); // Initial check for screen size
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
    };
  }, []); // Empty dependency array to run effect only once on mount

  const renderTextKey = () => {
    const words = textKey.split(" ");
    if (words.length > 50 && !isExpanded) {
      return words.slice(0, 50).join(" ") + " ...";
    }
    return textKey;
  };

  if (!node || !node.frontmatter) {
    return null;
  }

  let titleKey = "title";
  let dateKey = "date";
  let keywordsKey = "keywords";
  let imageKey = "hero_img_src";
  let textKey;

  if (p_type === "projects" || p_type === "pub") {
    textKey = node.frontmatter.abstract;
  } else if (p_type === "blog" || p_type === "models") {
    textKey = node.excerpt;
  } else {
    textKey = node.excerpt;
  }

  const image = getImage(node.frontmatter[imageKey]);

  return (
    <article
      title={node.frontmatter[titleKey]}
      key={node.id}
      className={
        isFeatured
          ? "hm-g-cd-fm-ft-wrp"
          : isMobile
            ? "hm-ng-cd-fm-oth-wrp-mob"
            : "hm-ng-cd-fm-oth-wrp"
      }
    >
      <>
        {/* Hero image */}
        {node.frontmatter.hero_img_src || PlaceholderImage ? (
          <div className="hm-cd-img-wrp">
            <Link to={`/${node.frontmatter.p_type}/${node.frontmatter.slug}`}>
              {node.frontmatter.hero_img_src ? (
                <GatsbyImage
                  title={node.frontmatter.title}
                  image={image}
                  alt={
                    node.frontmatter.hero_img_alt
                      ? node.frontmatter.hero_img_alt
                      : node.frontmatter.title
                  }
                  className={isFeatured ? "hm-cd-img-ft" : "hm-cd-img-oth"}
                />
              ) : (
                <img
                  alt="Placeholder"
                  src={PlaceholderImage}
                  title={node.frontmatter.title}
                  className={isFeatured ? "hm-cd-img-ft" : "hm-cd-img-oth"}
                />
              )}
            </Link>
          </div>
        ) : null}

        {/* Title & date */}
        <section className={`${isFeatured ? "hm-fm-ft-flx" : "hm-fm-oth-flx"}`}>
          <div className="hm-fm-wrp">
            {/* Title */}
            {node.frontmatter.title ? (
              <h4 style={{fontStyle: "normal"}} className={isFeatured ? "hm-fm-tit-ft" : "hm-fm-tit-oth"}>
                <Link
                  to={`/${p_type}/${node.frontmatter.slug}`}
                  className="g-hidden-link"
                >
                  {node.frontmatter.title}
                </Link>
              </h4>
            ) : null}

            {/* Date */}
            {isMobile && !isFeatured
              ? null
              : node.frontmatter.date && (
                  <p
                    className="hm-date"
                    title={
                      isFeatured
                        ? formatFullDateMonthYear(node.frontmatter[dateKey])
                        : formatMonthYear(node.frontmatter[dateKey])
                    }
                  >
                    {isFeatured
                      ? formatFullDateMonthYear(node.frontmatter[dateKey])
                      : formatMonthYear(node.frontmatter[dateKey])}{" "}
                  </p>
                )}
          </div>

          {/* Only Pub: Authors, DOI, Journal */}
          {p_type === "pub" && <PubFrontmatter p_type="pub" node={node} />}

          {isMobile && !isFeatured ? null : (
            <KeywordButtonsGeneral
              keywords={node.frontmatter[keywordsKey]}
              showAll={isFeatured}
              sliceAt={!isFeatured ? 3 : undefined}
            />
          )}

          {isFeatured && textKey && (
            <p className="hm-ft-p">
              {renderTextKey()}
              {textKey.split(" ").length > 50 && (
                <ShowMoreButton
                  isExpanded={isExpanded}
                  toggleExpand={toggleExpand}
                />
              )}
            </p>
          )}

          {isFeatured && (
            <div className="g-rml-wrp">
              <ReadMoreLink
                slug={node.frontmatter.slug}
                pType={node.frontmatter.p_type}
              />
            </div>
          )}
        </section>
      </>
    </article>
  );
};
